  ?coin wdt:P31 wd:Q415167;
         rdfs:label ?label.
  FILTER (CONTAINS(UCASE(?label), "ASHVAMEDHA"))
  ?coin wdt:P1674 ?issuer.
  ?issuer wdt:P76 ?ritual.
  ?ritual rdfs:label ?ritualLabel.
  FILTER (LANG(?ritualLabel) = "en" && CONTAINS(UCASE(?ritualLabel), "ASHVAMEDHA"))
}

